package com.pos;
import javax.swing.*; import java.awt.*; import java.sql.*;
public class CashierShiftPanel extends JPanel { private final UserSession s;private final QueryTableModel m=new QueryTableModel();private final JTable t=new JTable(m);private final JTextField employee=new JTextField(5),terminal=new JTextField("1",5),opening=new JTextField("1000",8),actual=new JTextField(8);
 public CashierShiftPanel(UserSession s){super(new BorderLayout(8,8));this.s=s;JPanel h=new JPanel(new BorderLayout());h.add(UIUtils.title("Cashier Shift and Cash Drawer"),BorderLayout.WEST);JButton refresh=new JButton("Refresh");h.add(refresh,BorderLayout.EAST);add(h,BorderLayout.NORTH);add(new JScrollPane(t),BorderLayout.CENTER);JPanel f=new JPanel();f.add(new JLabel("Employee ID"));f.add(employee);f.add(new JLabel("Terminal ID"));f.add(terminal);f.add(new JLabel("Opening Cash"));f.add(opening);JButton open=new JButton("Open Shift");f.add(open);f.add(new JLabel("Actual Cash at Close"));f.add(actual);JButton close=new JButton("Close Selected Shift");f.add(close);add(f,BorderLayout.SOUTH);refresh.addActionListener(e->load());open.addActionListener(e->open());close.addActionListener(e->close());load();}
 private void load(){try{m.load("SELECT shift_id,terminal_id,employee_id,shift_date,opened_at,closed_at,opening_cash,expected_cash,actual_cash,variance,status FROM cashier_shifts ORDER BY shift_id DESC");}catch(Exception e){UIUtils.error(this,e);}}
 private void open(){try{int id=POSService.openShift(Integer.parseInt(employee.getText()),Integer.parseInt(terminal.getText()),Double.parseDouble(opening.getText()));Audit.log(s,"OPEN_SHIFT","shift="+id);load();UIUtils.info(this,"Shift opened. Use Shift ID "+id+" during POS checkout.");}catch(Exception e){UIUtils.error(this,e);}}
 private void close(){int r=t.getSelectedRow();if(r<0)return;try{int id=Integer.parseInt(String.valueOf(t.getValueAt(t.convertRowIndexToModel(r),0)));POSService.closeShift(id,Double.parseDouble(actual.getText()),s.userId);Audit.log(s,"CLOSE_SHIFT","shift="+id);load();}catch(Exception e){UIUtils.error(this,e);}}
}
